  171 => 
  array (
    'section' => 'HAND HYGIENE SKILLS',
    'item' => '-2. Follow Isolation Protocols-Enhanced Barrier Precautions (EBP), Standard Precautions, Transmission-Based Precautions-Airborne, Contact, Droplet; Use of proper PPE',
    'position_titles' => 
    array (
      0 => 'Charge Nurse',
      1 => 'Director of Nursing',
      2 => 'IP Nurse',
      3 => 'Licensed Nurse',
      4 => 'Licensed Vocational Nurse',
      5 => 'Registered Nurse',
    ),
    'order' => 573,
  ),
  172 => 
  array (
    'section' => 'HAND HYGIENE SKILLS',
    'item' => '-3. Bring Treatment Cart to resident’s doorway. Face cart towards doorway. If you are able to visually see Treatment Cart from resident’s bedside, it is not necessary to lock cart. However, if you cannot see the cart, lock cart while you are doing the treatment in the resident’s room.',
    'position_titles' => 
    array (
      0 => 'Charge Nurse',
      1 => 'Director of Nursing',
      2 => 'IP Nurse',
      3 => 'Licensed Nurse',
      4 => 'Licensed Vocational Nurse',
      5 => 'Registered Nurse',
    ),
    'order' => 574,
  ),
  173 => 
  array (
    'section' => 'HAND HYGIENE SKILLS',
    'item' => '-4. Review treatment order in eMAR/TAR. Prepare supplies for treatment. Pour normal saline or substitute into medicine cup. If the order includes an ointment, do not bring tube into room. Squirt just enough ointment into medicine cup. May use clean cotton tips or tongue depressors as applicators. Make sure that you have at least two pairs of gloves. They do not need to be sterile, unless it is a sterile procedure.',
    'position_titles' => 
    array (
      0 => 'Charge Nurse',
      1 => 'Director of Nursing',
      2 => 'IP Nurse',
      3 => 'Licensed Nurse',
      4 => 'Licensed Vocational Nurse',
      5 => 'Registered Nurse',
    ),
    'order' => 575,
  ),
  174 => 
  array (
    'section' => 'HAND HYGIENE SKILLS',
    'item' => '-5. Place supplies on resident’s overhead bed table. A paper plate may be used, plastic bag, etc, as a barrier, to lay supplies on top of. Arrange dressings, cut tape, etc.',
    'position_titles' => 
    array (
      0 => 'Charge Nurse',
      1 => 'Director of Nursing',
      2 => 'IP Nurse',
      3 => 'Licensed Nurse',
      4 => 'Licensed Vocational Nurse',
      5 => 'Registered Nurse',
    ),
    'order' => 576,
  ),
  175 => 
  array (
    'section' => 'HAND HYGIENE SKILLS',
    'item' => '-6. Pull curtain around resident’s bed for privacy.',
    'position_titles' => 
